Создать frontend/composables/useContact.ts:

interface ContactForm {
  name: string
  email: string
  phone: string
  subject: string
  message: string
  turnstile_token: string
}

interface ContactPageSettings {
  contact_page_text: string | null
  contact_email: string | null
}

export const useContact = () => {
  const config = useRuntimeConfig()

  const submitContact = async (form: ContactForm) => {
    return useFetch('/api/v1/contact', {
      method: 'POST',
      body: form,
      baseURL: config.public.apiBase
    })
  }

  const fetchContactSettings = async () => {
    // GET /api/v1/admin/settings/contact — для отображения приветственного текста
    // ВАЖНО: этот endpoint публично возвращает только contact_page_text (не email)
    // Используем отдельный публичный endpoint если он будет создан backend-агентом,
    // или запрашиваем через admin (если страница доступна только авторизованным).
    // Для публичной страницы: backend-агент должен добавить GET /api/v1/contact/settings (без auth)
    // Если endpoint не реализован — использовать заглушку пустого текста
    return useFetch<ContactPageSettings>('/api/v1/contact/settings', {
      baseURL: config.public.apiBase
    })
  }

  return { submitContact, fetchContactSettings }
}
